mapper.select:
SELECT id, source_type, source_id, target_type, target_id, link_type, note, created_at
FROM ielts_content_links
WHERE id = #{id,jdbcType=OTHER}

SELECT COUNT(*) FROM ielts_content_links
WHERE target_type = #{targetType}
  AND target_id   = #{targetId,jdbcType=OTHER}

mapper.delete:
DELETE FROM ielts_content_links
WHERE source_type = #{sourceType}
  AND source_id   = #{sourceId,jdbcType=OTHER}

DELETE FROM ielts_content_links
WHERE target_type = #{targetType}
  AND target_id   = #{targetId,jdbcType=OTHER}
